export function roomTagSprite(
  cxM: number,
  czM: number,
  name: string,
  number: string | null | undefined,
  areaMm2: number,
  pickId?: string,
  fontScale = 1,
): THREE.Sprite {
  const scaleMul = Number.isFinite(fontScale) && fontScale > 0 ? fontScale : 1;
  const doc = typeof globalThis.document !== 'undefined' ? globalThis.document : null;
  const emptySprite = (): THREE.Sprite => {
    const mat = new THREE.SpriteMaterial({ color: getPlanPalette().tagBg, transparent: true, opacity: 0.92 });
    const s = new THREE.Sprite(mat);
    s.position.set(cxM, PLAN_Y + 0.003, czM);
    s.scale.set(0.12 * scaleMul, 0.07 * scaleMul, 1);
    s.renderOrder = 10;
    s.userData.planAnnotationOverlay = true;
    if (pickId) s.userData.bimPickId = pickId;
    return s;
  };
  if (!doc?.createElement) return emptySprite();
  const viteMode =
    typeof import.meta !== 'undefined' &&
    typeof (import.meta as { env?: { MODE?: string } }).env?.MODE === 'string'
      ? (import.meta as { env: { MODE: string } }).env.MODE
      : '';
  if (viteMode === 'test') return emptySprite();

  const dpr =
    typeof (globalThis as { devicePixelRatio?: number }).devicePixelRatio === 'number'
      ? (globalThis as { devicePixelRatio: number }).devicePixelRatio
      : 1;

  const namePx = Math.round(14 * Math.min(Math.max(dpr, 1), 2));
  const subPx = Math.round(12 * Math.min(Math.max(dpr, 1), 2));
  const lineH = Math.ceil(namePx * 1.4);
  const pad = 10;

  const safeName = (name ?? '').trim() || '—';
  const safeNum = (number ?? '').trim();
  const areaText = `${(areaMm2 / 1_000_000).toFixed(1)} m²`;
  const rowsToMeasure = [safeName, ...(safeNum ? [safeNum] : []), areaText];

  const measCanvas = doc.createElement('canvas');
  const measCtx = measCanvas.getContext('2d');
  if (!measCtx) return emptySprite();
  measCtx.font = `bold ${namePx}px Inter,system-ui,sans-serif`;
  let maxW = measCtx.measureText(safeName).width;
  measCtx.font = `${subPx}px Inter,system-ui,sans-serif`;
  for (const row of rowsToMeasure.slice(1)) {
    const w = measCtx.measureText(row).width;
    if (w > maxW) maxW = w;
  }

  const canvasW = Math.ceil(maxW + pad * 3);
  const rowCount = rowsToMeasure.length;
  const canvasH = Math.ceil(rowCount * lineH + pad * 2);

  const canvas = doc.createElement('canvas');
  canvas.width = canvasW;
  canvas.height = canvasH;
  let ctx: CanvasRenderingContext2D | null;
  try {
    ctx = canvas.getContext('2d');
  } catch {
    ctx = null;
  }
  if (!ctx) return emptySprite();

  const r = pad;
  ctx.globalAlpha = 0.92;
  ctx.fillStyle = getPlanPalette().tagBg;
  ctx.strokeStyle = 'rgba(255,255,255,0.78)';
  ctx.lineWidth = 4;
  ctx.beginPath();
  ctx.moveTo(r, 0);
  ctx.lineTo(canvasW - r, 0);
  ctx.arcTo(canvasW, 0, canvasW, r, r);
  ctx.lineTo(canvasW, canvasH - r);
  ctx.arcTo(canvasW, canvasH, canvasW - r, canvasH, r);
  ctx.lineTo(r, canvasH);
  ctx.arcTo(0, canvasH, 0, canvasH - r, r);
  ctx.lineTo(0, r);
  ctx.arcTo(0, 0, r, 0, r);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'alphabetic';
  ctx.fillStyle = getPlanPalette().tagText;

  let baselineY = pad + lineH * 0.82;
  ctx.font = `bold ${namePx}px Inter,system-ui,sans-serif`;
  ctx.fillText(safeName, canvasW / 2, baselineY);
  baselineY += lineH;

  ctx.font = `${subPx}px Inter,system-ui,sans-serif`;
  if (safeNum) {
    ctx.fillText(safeNum, canvasW / 2, baselineY);
    baselineY += lineH;
  }
  ctx.fillText(areaText, canvasW / 2, baselineY);

  const texture = new THREE.CanvasTexture(canvas);
  texture.needsUpdate = true;
  const mat = new THREE.SpriteMaterial({ map: texture, transparent: true, depthTest: true, depthWrite: false });
  const sprite = new THREE.Sprite(mat);
  sprite.position.set(cxM, PLAN_Y + 0.003, czM);
  const baselineSize = 72;
  sprite.scale.set(
    0.22 * (canvasW / baselineSize) * scaleMul,
    0.22 * (canvasH / baselineSize) * scaleMul,
    1,
  );
  sprite.renderOrder = 10;
  sprite.userData.planAnnotationOverlay = true;
  if (pickId) sprite.userData.bimPickId = pickId;
  return sprite;
}

